import React, { useState } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';

const App = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [scanInput, setScanInput] = useState('AAPL,MSFT,GOOGL,TSLA,NVDA');
  const [scanResults, setScanResults] = useState([]);
  const [selectedStock, setSelectedStock] = useState(null);
  const [loading, setLoading] = useState(false);

  const generateChartData = () => {
    return Array.from({ length: 24 }, (_, i) => ({
      time: `${i}:00`,
      price: Math.random() * 50 + 100,
      volume: Math.random() * 1000000
    }));
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const url = isSignUp ? 'http://localhost:5001/api/auth/register' : 'http://localhost:5001/api/auth/login';
      const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isSignUp ? { email, password, name } : { email, password }) });
      const data = await res.json();
      if (data.token) {
        localStorage.setItem('token', data.token);
        setIsLoggedIn(true);
        setPage('dashboard');
      } else {
        alert('Error: ' + (data.error || 'Failed'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const handleScan = async (e) => {
    e.preventDefault();
    setLoading(true);
    const tickers = scanInput.split(',').map(t => t.trim());
    const token = localStorage.getItem('token');
    try {
      const res = await fetch('http://localhost:5001/api/scan', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token }, body: JSON.stringify({ tickers }) });
      const data = await res.json();
      setScanResults(data.results || []);
      setSelectedStock(null);
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  if (page === 'landing') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)', minHeight: '100vh', color: 'white' }}>
        <nav style={{ padding: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid rgba(148,163,184,0.1)' }}>
          <h1 style={{ margin: 0, fontSize: '28px', color: '#10b981' }}>Bailey's Gauge</h1>
          <div style={{ display: 'flex', gap: '1rem' }}>
            <button onClick={() => { setIsSignUp(false); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: 'transparent', color: '#10b981', border: '2px solid #10b981', borderRadius: '8px', cursor: 'pointer' }}>Sign In</button>
            <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>Sign Up</button>
          </div>
        </nav>
        <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '4rem 2rem', textAlign: 'center' }}>
          <h2 style={{ fontSize: '48px', marginBottom: '1rem' }}>Professional Day Trading Scanner</h2>
          <p style={{ fontSize: '20px', color: '#94a3b8', marginBottom: '2rem' }}>Find winning day trades with real-time technical analysis. Better than AskLivemore.</p>
          <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '1rem 2rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', fontSize: '18px' }}>Get Started Free</button>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '2rem', marginTop: '4rem' }}>
            {[{ icon: '📊', title: 'Real-Time Charts', desc: 'Live price action & patterns' }, { icon: '⚡', title: 'Day Trade Signals', desc: 'Optimized for quick trades' }, { icon: '📈', title: 'Technical Analysis', desc: 'RSI, MACD, Bollinger Bands' }, { icon: '🎯', title: 'Smart Alerts', desc: 'Get notified of opportunities' }].map((f, i) => (
              <div key={i} style={{ background: 'rgba(30,41,59,0.8)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.2)' }}>
                <div style={{ fontSize: '40px', marginBottom: '1rem' }}>{f.icon}</div>
                <h3 style={{ marginBottom: '0.5rem' }}>{f.title}</h3>
                <p style={{ color: '#94a3b8', fontSize: '14px' }}>{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (page === 'auth') {
    return (
      <div style={{ padding: '2rem', textAlign: 'center', background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)', color: 'white', minHeight: '100vh' }}>
        <div style={{ maxWidth: '400px', margin: '0 auto', background: 'rgba(30,41,59,0.9)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.2)' }}>
          <h2 style={{ marginBottom: '2rem' }}>{isSignUp ? 'Create Account' : 'Sign In'}</h2>
          <form onSubmit={handleAuth}>
            {isSignUp && <input type="text" placeholder="Name" value={name} onChange={(e) => setName(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.5)', color: 'white' }} required />}
            <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.5)', color: 'white' }} required />
            <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.5)', color: 'white' }} required />
            <button type="submit" style={{ width: '100%', padding: '0.75rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>{loading ? 'Loading...' : (isSignUp ? 'Sign Up' : 'Sign In')}</button>
          </form>
          <p style={{ marginTop: '1rem', color: '#94a3b8' }}>{isSignUp ? 'Have account?' : 'No account?'} <button onClick={() => setIsSignUp(!isSignUp)} style={{ background: 'none', border: 'none', color: '#10b981', cursor: 'pointer', fontWeight: 'bold' }}>{isSignUp ? 'Sign In' : 'Sign Up'}</button></p>
          <button onClick={() => setPage('landing')} style={{ width: '100%', marginTop: '1rem', padding: '0.75rem', background: 'transparent', color: '#94a3b8', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '8px', cursor: 'pointer' }}>Back</button>
        </div>
      </div>
    );
  }

  if (page === 'dashboard' && isLoggedIn) {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)', minHeight: '100vh', color: 'white', padding: '2rem' }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
            <h1 style={{ margin: 0, color: '#10b981' }}>Day Trading Scanner</h1>
            <button onClick={() => { localStorage.removeItem('token'); setIsLoggedIn(false); setPage('landing'); }} style={{ padding: '0.5rem 1rem', background: '#ef4444', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Logout</button>
          </div>

          <form onSubmit={handleScan} style={{ marginBottom: '2rem', display: 'flex', gap: '1rem', background: 'rgba(30,41,59,0.8)', padding: '1.5rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.2)' }}>
            <input type="text" value={scanInput} onChange={(e) => setScanInput(e.target.value)} placeholder="Enter tickers: AAPL,MSFT,GOOGL" style={{ flex: 1, padding: '0.75rem', borderRadius: '8px', border: 'none', background: 'rgba(15,23,42,0.5)', color: 'white' }} />
            <button type="submit" disabled={loading} style={{ padding: '0.75rem 2rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', opacity: loading ? 0.5 : 1 }}>{loading ? 'Scanning...' : 'Scan'}</button>
          </form>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem', marginBottom: '2rem' }}>
            {scanResults.slice(0, 4).map((stock, i) => (
              <div key={i} onClick={() => setSelectedStock(stock)} style={{ background: 'rgba(30,41,59,0.8)', padding: '1.5rem', borderRadius: '12px', border: selectedStock?.ticker === stock.ticker ? '2px solid #10b981' : '1px solid rgba(148,163,184,0.2)', cursor: 'pointer', transition: 'all 0.3s' }}>
                <h3 style={{ margin: '0 0 1rem', color: '#10b981', fontSize: '24px' }}>{stock.ticker}</h3>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                  <div>
                    <p style={{ color: '#94a3b8', margin: '0.5rem 0' }}>Price: <span style={{ color: 'white', fontWeight: 'bold' }}>${stock.price}</span></p>
                    <p style={{ color: stock.change > 0 ? '#10b981' : '#ef4444', margin: '0.5rem 0', fontWeight: 'bold' }}>{stock.change > 0 ? '▲' : '▼'} {stock.change}%</p>
                  </div>
                  <div>
                    <p style={{ color: '#94a3b8', margin: '0.5rem 0' }}>RSI: <span style={{ color: stock.rsi > 70 ? '#ef4444' : stock.rsi < 30 ? '#10b981' : 'white', fontWeight: 'bold' }}>{stock.rsi}</span></p>
                    <p style={{ color: '#94a3b8', margin: '0.5rem 0' }}>Signal: <span style={{ color: stock.signal > 70 ? '#10b981' : stock.signal < 30 ? '#ef4444' : 'white', fontWeight: 'bold' }}>{stock.signal}</span></p>
                  </div>
                </div>
                <div style={{ background: 'rgba(15,23,42,0.5)', padding: '0.75rem', borderRadius: '6px', fontSize: '12px', color: stock.breakout ? '#10b981' : '#94a3b8' }}>
                  {stock.breakout ? '🔥 BREAKOUT' : 'Consolidating'}
                </div>
              </div>
            ))}
          </div>

          {selectedStock && (
            <div style={{ background: 'rgba(30,41,59,0.8)', padding: '2rem', borderRadius: '12px', border: '1px solid rgba(148,163,184,0.2)' }}>
              <h2 style={{ marginTop: 0, color: '#10b981' }}>{selectedStock.ticker} - 24H Price Action</h2>
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={generateChartData()}>
                  <CartesianGrid strokeDasharray="3 3" stroke="rgba(148,163,184,0.2)" />
                  <XAxis dataKey="time" stroke="#94a3b8" />
                  <YAxis stroke="#94a3b8" />
                  <Tooltip contentStyle={{ background: 'rgba(15,23,42,0.9)', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '8px', color: 'white' }} />
                  <Line type="monotone" dataKey="price" stroke="#10b981" strokeWidth={2} dot={false} />
                </LineChart>
              </ResponsiveContainer>
              <div style={{ marginTop: '2rem', display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem' }}>
                <div style={{ background: 'rgba(15,23,42,0.5)', padding: '1rem', borderRadius: '8px' }}>
                  <p style={{ color: '#94a3b8', margin: '0 0 0.5rem' }}>P/E Ratio</p>
                  <p style={{ color: 'white', fontSize: '20px', margin: 0, fontWeight: 'bold' }}>{selectedStock.pe_ratio}</p>
                </div>
                <div style={{ background: 'rgba(15,23,42,0.5)', padding: '1rem', borderRadius: '8px' }}>
                  <p style={{ color: '#94a3b8', margin: '0 0 0.5rem' }}>Dividend Yield</p>
                  <p style={{ color: '#10b981', fontSize: '20px', margin: 0, fontWeight: 'bold' }}>{selectedStock.dividend_yield}%</p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return null;
};

export default App;
